import React, { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../../contexts/AuthContext';
import { 
  Clock, 
  CheckCircle, 
  AlertCircle, 
  MapPin, 
  Calendar, 
  User,
  ArrowLeft,
  Download,
  Trash2,
  Camera,
  Edit,
  Settings,
  UserPlus,
  Zap,
  Tag,
  X,
  ChevronLeft,
  ChevronRight,
  ZoomIn,
  Image as ImageIcon,
  Maximize2
} from 'lucide-react';
import toast from 'react-hot-toast';

/* ─────────── Image Lightbox Component ─────────── */
const ImageLightbox = ({ images, currentIndex, onClose, onPrev, onNext, baseURL }) => {
  useEffect(() => {
    const handleKey = (e) => {
      if (e.key === 'Escape') onClose();
      if (e.key === 'ArrowLeft') onPrev();
      if (e.key === 'ArrowRight') onNext();
    };
    window.addEventListener('keydown', handleKey);
    return () => window.removeEventListener('keydown', handleKey);
  }, [onClose, onPrev, onNext]);

  const image = images[currentIndex];
  if (!image) return null;

  return (
    <div 
      className="fixed inset-0 z-50 flex items-center justify-center"
      style={{ backgroundColor: 'rgba(0,0,0,0.92)' }}
      onClick={onClose}
    >
      {/* Close button */}
      <button
        onClick={onClose}
        className="absolute top-4 right-4 z-50 p-2 rounded-full bg-white/10 hover:bg-white/20 text-white transition-all backdrop-blur-sm"
        style={{ border: '1px solid rgba(255,255,255,0.15)' }}
      >
        <X className="h-6 w-6" />
      </button>

      {/* Counter */}
      <div 
        className="absolute top-4 left-1/2 -translate-x-1/2 z-50 px-4 py-2 rounded-full text-white text-sm font-medium backdrop-blur-sm"
        style={{ backgroundColor: 'rgba(255,255,255,0.1)', border: '1px solid rgba(255,255,255,0.15)' }}
      >
        {currentIndex + 1} / {images.length}
      </div>

      {/* Prev button */}
      {images.length > 1 && (
        <button
          onClick={(e) => { e.stopPropagation(); onPrev(); }}
          className="absolute left-4 z-50 p-3 rounded-full bg-white/10 hover:bg-white/20 text-white transition-all backdrop-blur-sm"
          style={{ border: '1px solid rgba(255,255,255,0.15)' }}
        >
          <ChevronLeft className="h-6 w-6" />
        </button>
      )}

      {/* Main image */}
      <div 
        className="max-w-[90vw] max-h-[85vh] flex items-center justify-center"
        onClick={(e) => e.stopPropagation()}
      >
        <img
          src={`${baseURL}${image.viewUrl}`}
          alt={image.fileName}
          className="max-w-full max-h-[85vh] object-contain rounded-lg"
          style={{ 
            boxShadow: '0 25px 50px -12px rgba(0,0,0,0.5)',
            animation: 'fadeScaleIn 0.3s ease-out'
          }}
        />
      </div>

      {/* Next button */}
      {images.length > 1 && (
        <button
          onClick={(e) => { e.stopPropagation(); onNext(); }}
          className="absolute right-4 z-50 p-3 rounded-full bg-white/10 hover:bg-white/20 text-white transition-all backdrop-blur-sm"
          style={{ border: '1px solid rgba(255,255,255,0.15)' }}
        >
          <ChevronRight className="h-6 w-6" />
        </button>
      )}

      {/* Image filename */}
      <div 
        className="absolute bottom-6 left-1/2 -translate-x-1/2 z-50 px-5 py-2.5 rounded-xl text-white text-sm backdrop-blur-sm"
        style={{ backgroundColor: 'rgba(255,255,255,0.1)', border: '1px solid rgba(255,255,255,0.15)' }}
      >
        {image.fileName}
      </div>

      <style>{`
        @keyframes fadeScaleIn {
          from { opacity: 0; transform: scale(0.95); }
          to { opacity: 1; transform: scale(1); }
        }
      `}</style>
    </div>
  );
};

/* ─────────── Main ComplaintDetail Component ─────────── */
const ComplaintDetail = () => {
  const { id } = useParams();
  const { api, user } = useAuth();
  const navigate = useNavigate();
  const [complaint, setComplaint] = useState(null);
  const [evidences, setEvidences] = useState([]);
  const [loading, setLoading] = useState(true);
  const [updatingStatus, setUpdatingStatus] = useState(false);
  const [workers, setWorkers] = useState([]);
  const [assigningWorker, setAssigningWorker] = useState(false);
  const [lightboxOpen, setLightboxOpen] = useState(false);
  const [lightboxIndex, setLightboxIndex] = useState(0);

  const isAdmin = user?.role === 'ADMIN' || user?.role === 'OWNER';

  // Base URL for image requests (same origin as API)
  const baseURL = api.defaults.baseURL ? api.defaults.baseURL.replace('/api', '') : 'http://localhost:8083';
  console.log('Base URL for images:', baseURL);

  useEffect(() => {
    fetchComplaint();
    fetchEvidences();
    if (isAdmin) {
      fetchWorkers();
    }
  }, [id, isAdmin]);

  const fetchWorkers = async () => {
    try {
      const response = await api.get('/workers/active');
      setWorkers(response.data.content || response.data || []);
    } catch (error) {
      console.error('Error fetching workers:', error);
    }
  };

  const handleStatusUpdate = async (newStatus) => {
    try {
      setUpdatingStatus(true);
      await api.put(`/complaints/${id}/status`, { status: newStatus });
      toast.success(`Status updated to ${newStatus.replace('_', ' ')}`);
      fetchComplaint(); // Refresh
    } catch (error) {
      console.error('Error updating status:', error);
      toast.error('Failed to update status');
    } finally {
      setUpdatingStatus(false);
    }
  };

  const fetchComplaint = async () => {
    try {
      const response = await api.get(`/complaints/${id}`);
      setComplaint(response.data);
    } catch (error) {
      console.error('Error fetching complaint:', error);
      toast.error('Failed to load complaint details');
    } finally {
      setLoading(false);
    }
  };

  const fetchEvidences = async () => {
    try {
      console.log('Fetching evidences for complaint ID:', id);
      const response = await api.get(`/files/complaint/${id}`);
      console.log('Evidences response:', response.data);
      const evidencesData = response.data || [];
      setEvidences(evidencesData);
      console.log('Evidences set:', evidencesData);

      // Log image URLs for debugging
      evidencesData.forEach((evidence, index) => {
        console.log(`Evidence ${index + 1}:`, {
          id: evidence.id,
          fileName: evidence.fileName,
          viewUrl: evidence.viewUrl,
          fullUrl: `${baseURL}${evidence.viewUrl}`
        });
      });
    } catch (error) {
      console.error('Error fetching evidences:', error);
      console.error('Error response:', error.response?.data);
      console.error('Error status:', error.response?.status);
      // Silently fail — evidences are optional
    }
  };

  const assignWorker = async (workerId) => {
    try {
      setAssigningWorker(true);
      await api.patch(`/complaints/${id}/assign`, { workerId: parseInt(workerId) });
      toast.success('Worker assigned successfully');
      fetchComplaint(); // Refresh
    } catch (error) {
      console.error('Error assigning worker:', error.response?.data || error);
      const errorMessage = error.response?.data?.message || 'Failed to assign worker';
      toast.error(errorMessage);
    } finally {
      setAssigningWorker(false);
    }
  };

  const openLightbox = useCallback((index) => {
    setLightboxIndex(index);
    setLightboxOpen(true);
    document.body.style.overflow = 'hidden';
  }, []);

  const closeLightbox = useCallback(() => {
    setLightboxOpen(false);
    document.body.style.overflow = '';
  }, []);

  const prevImage = useCallback(() => {
    setLightboxIndex((prev) => (prev - 1 + evidences.length) % evidences.length);
  }, [evidences.length]);

  const nextImage = useCallback(() => {
    setLightboxIndex((prev) => (prev + 1) % evidences.length);
  }, [evidences.length]);

  const getStatusIcon = (status) => {
    switch (status) {
      case 'PENDING':
        return <Clock className="h-5 w-5 text-yellow-600" />;
      case 'IN_PROGRESS':
        return <AlertCircle className="h-5 w-5 text-blue-600" />;
      case 'RESOLVED':
        return <CheckCircle className="h-5 w-5 text-green-600" />;
      default:
        return <Clock className="h-5 w-5 text-gray-600" />;
    }
  };

  const getStatusClass = (status) => {
    switch (status) {
      case 'PENDING':
        return 'bg-yellow-100 text-yellow-800';
      case 'IN_PROGRESS':
        return 'bg-blue-100 text-blue-800';
      case 'RESOLVED':
        return 'bg-green-100 text-green-800';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  const getPriorityClass = (priority) => {
    switch (priority) {
      case 'LOW':
        return 'bg-gray-100 text-gray-800';
      case 'MEDIUM':
        return 'bg-orange-100 text-orange-800';
      case 'HIGH':
        return 'bg-red-100 text-red-800';
      case 'URGENT':
        return 'bg-purple-100 text-purple-800';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  const downloadFile = async (evidence) => {
    try {
      const response = await api.get(evidence.downloadUrl, {
        responseType: 'blob'
      });

      const url = window.URL.createObjectURL(new Blob([response.data]));
      const link = document.createElement('a');
      link.href = url;
      link.download = evidence.fileName;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      window.URL.revokeObjectURL(url);
      toast.success('File downloaded!');
    } catch (error) {
      console.error('Error downloading file:', error);
      toast.error('Failed to download file');
    }
  };

  const deleteEvidence = async (evidenceId) => {
    if (!window.confirm('Are you sure you want to delete this evidence?')) {
      return;
    }

    try {
      await api.delete(`/files/${evidenceId}`);
      setEvidences(evidences.filter(e => e.id !== evidenceId));
      toast.success('Evidence deleted successfully');
    } catch (error) {
      console.error('Error deleting evidence:', error);
      toast.error('Failed to delete evidence');
    }
  };

  const deleteComplaint = async () => {
    if (!window.confirm('Are you sure you want to delete this complaint? This action cannot be undone.')) {
      return;
    }

    try {
      await api.delete(`/complaints/${id}`);
      toast.success('Complaint deleted successfully');
      navigate('/complaints');
    } catch (error) {
      console.error('Error deleting complaint:', error);
      toast.error('Failed to delete complaint');
    }
  };

  const formatFileSize = (bytes) => {
    if (!bytes) return '0 B';
    if (bytes < 1024) return bytes + ' B';
    if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + ' KB';
    return (bytes / 1024 / 1024).toFixed(2) + ' MB';
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary-600"></div>
      </div>
    );
  }

  if (!complaint) {
    return (
      <div className="text-center py-8">
        <p className="text-gray-500">Complaint not found</p>
      </div>
    );
  }

  return (
    <div className="p-6">
      {/* Lightbox */}
      {lightboxOpen && evidences.length > 0 && (
        <ImageLightbox
          images={evidences}
          currentIndex={lightboxIndex}
          onClose={closeLightbox}
          onPrev={prevImage}
          onNext={nextImage}
          baseURL={baseURL}
        />
      )}

      {/* Header Section */}
      <div className="bg-gradient-to-r from-red-600 to-red-700 rounded-xl p-8 text-white flex flex-col sm:flex-row sm:items-center justify-between gap-6 overflow-hidden relative shadow-lg mb-6">
        <div className="relative z-10">
          <button
            onClick={() => navigate(-1)}
            className="inline-flex items-center text-primary-100 hover:text-white transition-colors mb-4 group"
          >
            <ArrowLeft className="h-5 w-5 mr-2 group-hover:-translate-x-1 transition-transform" />
            Back to Complaints
          </button>
          <h1 className="text-3xl font-bold mb-2">Complaint Details</h1>
          <p className="text-primary-100">View and manage complaint information</p>
        </div>
        <div className="relative z-10 flex items-center space-x-3">
          <span className={`inline-flex items-center px-4 py-2 rounded-full text-sm font-bold bg-white/20 backdrop-blur-sm`}>
            {getStatusIcon(complaint.status)}
            <span className="ml-2">{complaint.status.replace('_', ' ')}</span>
          </span>
        </div>
      </div>

      {/* Side-by-Side Layout */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Left Side - Complaint Details (2 columns) */}
        <div className="lg:col-span-2 space-y-6">
          {/* Main Content Card */}
          <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
            <div className="p-6">
              {/* Title and Edit Button */}
              <div className="flex items-start justify-between mb-6 pb-6 border-b border-gray-200">
                <div className="flex-1">
                  <h2 className="text-xl font-semibold text-gray-900 mb-3">{complaint.title}</h2>
                  <div className="flex items-center space-x-3">
                    <span className={`inline-flex items-center px-3 py-1 rounded-full text-xs font-medium ${getStatusClass(complaint.status)}`}>
                      {getStatusIcon(complaint.status)}
                      <span className="ml-1">{complaint.status.toLowerCase().replace('_', ' ')}</span>
                    </span>
                    <span className={`inline-flex items-center px-3 py-1 rounded-full text-xs font-medium ${getPriorityClass(complaint.priority)}`}>
                      {complaint.priority.toLowerCase()}
                    </span>
                  </div>
                </div>
                <Link
                  to={`/complaints/${id}/edit`}
                  className="inline-flex items-center px-4 py-2 border border-transparent rounded-lg shadow-sm text-sm font-medium text-white bg-primary-600 hover:bg-primary-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-primary-500"
                >
                  <Edit className="h-4 w-4 mr-2" />
                  Edit
                </Link>
              </div>

              {/* Description */}
              <div className="mb-6">
                <h3 className="text-lg font-medium text-gray-900 mb-3">Description</h3>
                <div className="bg-gray-50 rounded-lg p-4">
                  <p className="text-gray-700 whitespace-pre-wrap">{complaint.description}</p>
                </div>
              </div>

              {/* Location Information */}
              <div className="mb-6">
                <h3 className="text-lg font-medium text-gray-900 mb-3">Location</h3>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                  {complaint.blockNumber && (
                    <div className="bg-gray-50 rounded-lg p-4">
                      <div className="flex items-center space-x-2">
                        <MapPin className="h-4 w-4 text-gray-400" />
                        <div>
                          <p className="text-sm text-gray-500">Block</p>
                          <p className="font-medium text-gray-900">{complaint.blockNumber}</p>
                        </div>
                      </div>
                    </div>
                  )}
                  {complaint.buildingNumber && (
                    <div className="bg-gray-50 rounded-lg p-4">
                      <div className="flex items-center space-x-2">
                        <MapPin className="h-4 w-4 text-gray-400" />
                        <div>
                          <p className="text-sm text-gray-500">Building</p>
                          <p className="font-medium text-gray-900">{complaint.buildingNumber}</p>
                        </div>
                      </div>
                    </div>
                  )}
                  {complaint.roomNumber && (
                    <div className="bg-gray-50 rounded-lg p-4">
                      <div className="flex items-center space-x-2">
                        <MapPin className="h-4 w-4 text-gray-400" />
                        <div>
                          <p className="text-sm text-gray-500">Room</p>
                          <p className="font-medium text-gray-900">{complaint.roomNumber}</p>
                        </div>
                      </div>
                    </div>
                  )}
                </div>
              </div>

              {/* Metadata */}
              <div className="border-t border-gray-200 pt-6">
                <h3 className="text-lg font-medium text-gray-900 mb-3">Details</h3>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                  <div className="bg-gray-50 rounded-lg p-4">
                    <div className="flex items-center space-x-2">
                      <User className="h-4 w-4 text-gray-400" />
                      <div>
                        <p className="text-sm text-gray-500">Reported by</p>
                        <p className="font-medium text-gray-900">{complaint.userName}</p>
                      </div>
                    </div>
                  </div>
                  <div className="bg-gray-50 rounded-lg p-4">
                    <div className="flex items-center space-x-2">
                      <Calendar className="h-4 w-4 text-gray-400" />
                      <div>
                        <p className="text-sm text-gray-500">Reported on</p>
                        <p className="font-medium text-gray-900">
                          {new Date(complaint.createdAt).toLocaleDateString()}
                        </p>
                      </div>
                    </div>
                  </div>
                  <div className="bg-gray-50 rounded-lg p-4">
                    <div className="flex items-center space-x-2">
                      <Tag className="h-4 w-4 text-gray-400" />
                      <div>
                        <p className="text-sm text-gray-500">Category</p>
                        <p className="font-medium text-gray-900">{complaint.assetCategory?.replace('_', ' ') || 'OTHER'}</p>
                      </div>
                    </div>
                  </div>
                  {complaint.workerName && (
                    <div className="bg-primary-50 rounded-lg p-4 border border-primary-100">
                      <div className="flex items-center space-x-2">
                        <User className="h-4 w-4 text-primary-600" />
                        <div>
                          <p className="text-sm text-primary-600">Assigned Worker</p>
                          <p className="font-bold text-primary-900">{complaint.workerName}</p>
                        </div>
                      </div>
                    </div>
                  )}
                </div>
              </div>
            </div>
          </div>

          {/* ─────────── Evidence / Image Gallery Section ─────────── */}
          <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
            <div className="flex items-center justify-between mb-5">
              <h3 className="text-lg font-medium text-gray-900 flex items-center">
                <Camera className="h-5 w-5 mr-2 text-primary-500" />
                Evidence & Attachments
                {evidences.length > 0 && (
                  <span className="ml-2 inline-flex items-center justify-center px-2.5 py-0.5 rounded-full text-xs font-bold bg-primary-100 text-primary-700">
                    {evidences.length}
                  </span>
                )}
              </h3>
            </div>

            {evidences.length === 0 ? (
              <div className="text-center py-12 bg-gray-50 rounded-xl border-2 border-dashed border-gray-200">
                <ImageIcon className="h-12 w-12 text-gray-300 mx-auto mb-3" />
                <p className="text-gray-500 font-medium">No images attached</p>
                <p className="text-gray-400 text-sm mt-1">Evidence images will appear here when uploaded</p>
              </div>
            ) : (
              <>
                {/* Image Grid */}
                <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
                  {evidences.map((evidence, index) => (
                    <div
                      key={evidence.id}
                      className="group relative rounded-xl overflow-hidden border border-gray-200 bg-gray-50 cursor-pointer"
                      style={{
                        aspectRatio: '4/3',
                        transition: 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)'
                      }}
                      onClick={() => openLightbox(index)}
                      onMouseEnter={(e) => {
                        e.currentTarget.style.transform = 'translateY(-2px)';
                        e.currentTarget.style.boxShadow = '0 12px 28px -6px rgba(0,0,0,0.15)';
                      }}
                      onMouseLeave={(e) => {
                        e.currentTarget.style.transform = 'translateY(0)';
                        e.currentTarget.style.boxShadow = 'none';
                      }}
                    >
                      {/* Thumbnail Image */}
                      <img
                        src={`${baseURL}${evidence.viewUrl}`}
                        alt={evidence.fileName}
                        className="w-full h-full object-cover"
                        style={{ transition: 'transform 0.4s ease' }}
                        onError={(e) => {
                          e.target.style.display = 'none';
                          e.target.nextSibling.style.display = 'flex';
                        }}
                      />
                      {/* Fallback if image fails to load */}
                      <div
                        className="w-full h-full items-center justify-center bg-gray-100"
                        style={{ display: 'none' }}
                      >
                        <ImageIcon className="h-10 w-10 text-gray-300" />
                      </div>

                      {/* Hover overlay */}
                      <div
                        className="absolute inset-0 flex flex-col items-center justify-center opacity-0 group-hover:opacity-100"
                        style={{
                          background: 'linear-gradient(to top, rgba(0,0,0,0.7) 0%, rgba(0,0,0,0.2) 50%, transparent 100%)',
                          transition: 'opacity 0.3s ease'
                        }}
                      >
                        <div className="absolute top-3 right-3 flex space-x-2">
                          <button
                            onClick={(e) => { e.stopPropagation(); openLightbox(index); }}
                            className="p-2 rounded-full bg-white/20 hover:bg-white/30 text-white backdrop-blur-sm"
                            style={{ border: '1px solid rgba(255,255,255,0.2)', transition: 'all 0.2s ease' }}
                            title="View full size"
                          >
                            <Maximize2 className="h-4 w-4" />
                          </button>
                          <button
                            onClick={(e) => { e.stopPropagation(); downloadFile(evidence); }}
                            className="p-2 rounded-full bg-white/20 hover:bg-white/30 text-white backdrop-blur-sm"
                            style={{ border: '1px solid rgba(255,255,255,0.2)', transition: 'all 0.2s ease' }}
                            title="Download"
                          >
                            <Download className="h-4 w-4" />
                          </button>
                          {isAdmin && (
                            <button
                              onClick={(e) => { e.stopPropagation(); deleteEvidence(evidence.id); }}
                              className="p-2 rounded-full bg-red-500/40 hover:bg-red-500/60 text-white backdrop-blur-sm"
                              style={{ border: '1px solid rgba(255,255,255,0.2)', transition: 'all 0.2s ease' }}
                              title="Delete"
                            >
                              <Trash2 className="h-4 w-4" />
                            </button>
                          )}
                        </div>

                        {/* Bottom file info */}
                        <div className="absolute bottom-0 left-0 right-0 p-3">
                          <p className="text-white text-xs font-medium truncate">{evidence.fileName}</p>
                          <p className="text-white/70 text-xs">{formatFileSize(evidence.fileSize)}</p>
                        </div>

                        {/* Center zoom icon */}
                        <ZoomIn className="h-8 w-8 text-white/80" />
                      </div>
                    </div>
                  ))}
                </div>

                {/* Gallery summary bar */}
                <div className="mt-4 flex items-center justify-between px-3 py-2.5 bg-gray-50 rounded-lg text-sm text-gray-500">
                  <span className="flex items-center">
                    <ImageIcon className="h-4 w-4 mr-1.5" />
                    {evidences.length} image{evidences.length !== 1 ? 's' : ''} attached
                  </span>
                  <span>
                    Total: {formatFileSize(evidences.reduce((acc, e) => acc + (e.fileSize || 0), 0))}
                  </span>
                </div>
              </>
            )}
          </div>
        </div>

        {/* Right Side - Admin Console (1 column, sticky) */}
        {isAdmin && (
          <div className="lg:col-span-1">
            <div className="sticky top-6 space-y-6">
              {/* Admin Console Card */}
              <div className="bg-white rounded-xl shadow-lg border border-gray-200 p-6">
                <div className="flex items-center space-x-2 mb-6 pb-4 border-b border-gray-200">
                  <Settings className="h-6 w-6 text-primary-600" />
                  <h3 className="text-xl font-bold text-gray-900">Admin Console</h3>
                </div>

                {/* Status Management */}
                <div className="mb-6">
                  <div className="flex items-center space-x-2 mb-4">
                    <Zap className="h-5 w-5 text-yellow-600" />
                    <h4 className="font-bold text-gray-900">Quick Status Update</h4>
                  </div>
                  <div className="space-y-2">
                    {['PENDING', 'IN_PROGRESS', 'RESOLVED', 'REJECTED'].map((status) => (
                      <button
                        key={status}
                        disabled={updatingStatus || complaint.status === status}
                        onClick={() => handleStatusUpdate(status)}
                        className={`w-full px-4 py-3 rounded-xl text-sm font-bold transition-all flex items-center justify-between ${
                          complaint.status === status
                            ? 'bg-primary-600 text-white shadow-lg'
                            : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                        }`}
                      >
                        <span>{status.replace('_', ' ')}</span>
                        {complaint.status === status && <CheckCircle className="h-4 w-4" />}
                        {updatingStatus && complaint.status === status && <span className="animate-pulse">...</span>}
                      </button>
                    ))}
                  </div>
                </div>

                {/* Worker Assignment */}
                <div className="mb-6 border-t border-gray-200 pt-6">
                  <div className="flex items-center space-x-2 mb-4">
                    <UserPlus className="h-5 w-5 text-blue-600" />
                    <h4 className="font-bold text-gray-900">Assign Worker</h4>
                  </div>
                  <div className="space-y-4">
                    <select
                      onChange={(e) => {
                        if (e.target.value) {
                          assignWorker(e.target.value);
                        }
                      }}
                      value={complaint.workerId || ""}
                      disabled={assigningWorker}
                      className="w-full px-4 py-3 rounded-xl text-sm border border-gray-300 focus:ring-2 focus:ring-primary-500 focus:border-primary-500 bg-gray-50"
                    >
                      <option value="">{complaint.workerName ? 'Change Worker' : 'Select Worker'}</option>
                      {workers.map(worker => (
                        <option key={worker.id} value={worker.id}>
                          {worker.name} ({worker.specialization || worker.department})
                        </option>
                      ))}
                    </select>
                    {complaint.workerName && (
                      <div className="p-3 bg-blue-50 text-blue-700 rounded-lg text-xs flex items-center">
                        <Zap className="h-4 w-4 mr-2" />
                        Currently assigned to {complaint.workerName}
                      </div>
                    )}
                  </div>
                </div>

                {/* Quick Actions */}
                <div className="border-t border-gray-200 pt-6">
                  <h4 className="font-bold text-gray-900 mb-4">Quick Actions</h4>
                  <div className="space-y-2">
                    <Link
                      to={`/complaints/${id}/edit`}
                      className="w-full inline-flex items-center justify-center px-4 py-3 border border-gray-300 rounded-xl text-sm font-medium text-gray-700 bg-white hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-primary-500"
                    >
                      <Edit className="h-4 w-4 mr-2" />
                      Edit Complaint
                    </Link>
                    <button
                      onClick={() => deleteComplaint()}
                      className="w-full inline-flex items-center justify-center px-4 py-3 border border-transparent text-sm font-medium rounded-xl text-white bg-red-600 hover:bg-red-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-red-500"
                    >
                      <Trash2 className="h-4 w-4 mr-2" />
                      Delete Complaint
                    </button>
                  </div>
                </div>
              </div>

              {/* Complaint Info Summary */}
              <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
                <h4 className="font-bold text-gray-900 mb-4">Complaint Info</h4>
                <div className="space-y-3 text-sm">
                  <div className="flex justify-between">
                    <span className="text-gray-500">ID:</span>
                    <span className="font-medium text-gray-900">#{complaint.id}</span>
                  </div>
                  <div className="flex justify-between">
                    <span className="text-gray-500">Status:</span>
                    <span className={`font-medium ${complaint.status === 'RESOLVED' ? 'text-green-600' : complaint.status === 'PENDING' ? 'text-yellow-600' : 'text-blue-600'}`}>
                      {complaint.status.replace('_', ' ')}
                    </span>
                  </div>
                  <div className="flex justify-between">
                    <span className="text-gray-500">Priority:</span>
                    <span className={`font-medium ${complaint.priority === 'URGENT' ? 'text-red-600' : complaint.priority === 'HIGH' ? 'text-orange-600' : 'text-gray-600'}`}>
                      {complaint.priority}
                    </span>
                  </div>
                  <div className="flex justify-between">
                    <span className="text-gray-500">Created:</span>
                    <span className="font-medium text-gray-900">
                      {new Date(complaint.createdAt).toLocaleDateString()}
                    </span>
                  </div>
                  <div className="flex justify-between">
                    <span className="text-gray-500">Attachments:</span>
                    <span className="font-medium text-gray-900">
                      {evidences.length} image{evidences.length !== 1 ? 's' : ''}
                    </span>
                  </div>
                  {complaint.resolvedAt && (
                    <div className="flex justify-between">
                      <span className="text-gray-500">Resolved:</span>
                      <span className="font-medium text-green-600">
                        {new Date(complaint.resolvedAt).toLocaleDateString()}
                      </span>
                    </div>
                  )}
                </div>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default ComplaintDetail;
